function paraForAndroid(content, sources,ydv) {
    let {
        java,
        cache,
        source
    } = this;
    let plcolor = getArguments(source.getVariable(), "plcolor");
    if (!plcolor) {
        plcolor = "#000000";
    }
    let tccolor = getArguments(source.getVariable(), "tccolor");
    if (!tccolor) {
        tccolor = "#ffffff";
    }

    const createSvg = this.createSvg.bind(this);

    return content.replace(/<p>(.*?)(?:<comment ident="([^"]*)" count="([^"]*)" \/>)?<\/p>/g,
        (match, text, url, count) => {
            if (url && count) {
                const click = 0;
                cache.putMemory(url, click);
                const encodedUrl = url;
                return `<p>${text}<img src="${createSvg(count, plcolor,tccolor,encodedUrl,sources,ydv)}"></p>`;
            } else {
                return `<p>${text}</p>`;
            }
        }
    );
}


function showCmt(url, sources,ydv) {
    let {
        java,
        cache
    } = this;
    const currentTime = Date.now();
    const click = cache.getFromMemory(url);
    let isqread = false;
    try {
        java.qread();
        isqread = true;
    } catch (e) {}
    if (click < 1 && !isqread && !ydv) {
        cache.putMemory(url, click + 1);
        return;
    } else {
        if (isqread) {
            java.startBrowserDp(url, sources + '段评');
        } else if (ydv) {
                java.showBrowser(url, java.ajax(url));
            } else {
               java.startBrowser(url, sources + '段评');
        }
    }
}



