jsLib:
function hitRateFilter(arr, keyWords = '', exactLeague = false) {
  if (!Array.isArray(arr)) return [];
  const words = keyWords
    .trim()
    .split(/\s+/)
    .filter(Boolean);

  if (!words.length) return arr.slice();

  const regs = words.map(w => new RegExp(w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i'));

  const extract = obj =>
    Object.values(obj)
      .map(String)
      .join(' ');

  const scored = [];

  for (let item of arr) {
  	 if (exactLeague) {
      let league = String(item.league || '');
      let hit = words.some(w => w == league);
      if (!hit) continue;
    }
    let hits = regs.reduce((n, r) => n + r.test(extract(item)), 0);
    if (hits) scored.push({ item, rate: hits / words.length });
  }

  scored.sort((a, b) => b.rate - a.rate);

  return scored.map(x => x.item);
}

