@js:
const isStrict = !baseUrl.endsWith("#");
const keys = decodeURI(baseUrl.split("#")?.[1] || "");

const html = result.replace(/^\s*(<li>.*?)<li>\s*$/gm, "$1</li>");

const doc = org.jsoup.Jsoup.parse(html);
const resList = [];

let currDate = "";

doc.select('[role="main"] li').forEach(li => {
    let divider = li.select('li[data-theme=b]');
    if (divider.size() > 0) {
        currDate = divider.text().trim();
        return;
    }

    let a = li.select('a').first();
    if (!a) return;

    let fullText = String(a.text());
    let title = fullText.replace(/^.*\d{2}:\d{2}/, '').trim();
    let league = li.select('.league').text().trim();
    let status = li.select('.close').size()  
                       ? "已结束" 
                       : li.select('.live').size()
                         ? "直播中"  
                         : '未开赛';

    let time = fullText.match(/\d{2}:\d{2}/)?.[0]
    let datetime = currDate + (time ? ' ' + time : '');
    let kind = [league, status];

    let id = a.attr('href');
    let links = doc.select(id).select("a")
                    .toArray()
                    .filter(link=>link.attr("href").startsWith("http"))
                    .map(String);
    let json = JSON.stringify(links);
    let url = `data:;base64,${java.base64Encode(json)},{"type":""}`

    resList.push({
        title,
        datetime,
        league,
        kind,
        url
    });
});

const results = hitRateFilter(resList, keys, isStrict);
if(results.length === 0){
	 results.push({
    title: `没有找到与“${keys}”相关的赛事`,
    datetime: "尽量缩短关键字，字越多，越搜不到"
  })
}
results

