                if (/🎧/.test(M("模式"))) {
                    java.put("dm", danmakuToLRC(dm));
                    //result = JSON.parse(data).data.durl[0].url;
                    result = json.dash.audio[1].baseUrl;
                } else {
                    result = generateMPD(json.dash);

                    //result = JSON.parse(data).data.durl[0].url
                }
            }
        } else if (/mp4/i.test(json.type)) {
            result = json.durl[0].url
        }
