function replace(content) {
    const FONT_CHARS = "内暴强情缝贪插逼操潮喷阴艳裸乳荡穴鸡淫苞奸胸射嫩肉骚性蒂茎陰騷奶屄成人药春迷尿粉肛龟头占精屌口狂蜜处女唇道阳虐虫妇液色颜熟交爽臀爆舔做爱欲吹自慰点gG玉幼援抽Bb水母狗户部要了奴小脚痒酥死我兽揉搓捏扣抠棍棒洞密美少摩腿春乱伦露漏浪开巨根菊巴黑豪好肥送艳被干拔乱理白刺体下面诱感快货比日妈你娘婊子配仙火叫在里子宫给聊照流群屁眼马无码友拳洞片黄偷禁套弄位脱光舒服溜舞丢还糜妻换妓招嫖娼aA毛Hh一夜本热推图书娃男抓浑圆饱满润湿滑丰腴韵尤物横陈存娇喘息麻桃透风腹长粗肿胀人紧夹吸撅起来雪发翘硕大胴双草坐挲跨柔软臂瘫媚秘破";
    const UNICODE_START = 0xE001;
    const iconRegex = /<i class="icon icon-uni([0-9A-Fa-f]{4})"><\/i>/g;

    return content
        .replace(iconRegex, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
        .replace(/[\uE001-\uE101]/g, char => {
            const index = char.charCodeAt(0) - UNICODE_START;
            return index === 43 ? "AV" : FONT_CHARS[index] || char;
        });
}

