        csh_1 = JSON.parse(source.getVariable());
        if (csh_1 == null) {
            error;
        } else {
            '';
        };
    } catch (e) {
        csh_1 = original;
        source.setVariable(JSON.stringify(csh_1, null, 2));
        java.toast("初始化成功")
    }

}



//获取源变量的值
function Get(e) {
    const {
        java,
        source,
        cookie
    } = this;
    var get = JSON.parse(source.getVariable());
    return get[e];
}

//按钮切换时改变源变量并刷新发现
function show(m, t) {
    const {
        java,
        source
    } = this;
    //源变量为空时刷新发现，重置源变量
    source.getVariable()==''?java.refreshExplore():'';//
    var data = JSON.parse(source.getVariable());
